const results = [];
for (const item of $input.all()) {
  const analysis = item.json;
  const original = $('准备数据').item.json;

  let report = '';
  if (typeof analysis.output === 'string') {
    report = analysis.output;
  } else if (analysis.message && analysis.message.content) {
    report = analysis.message.content;
  } else if (analysis.choices && analysis.choices[0] && analysis.choices[0].message) {
    report = analysis.choices[0].message.content;
  } else if (typeof analysis.text === 'string') {
    report = analysis.text;
  } else if (typeof analysis.content === 'string') {
    report = analysis.content;
  } else {
    report = JSON.stringify(analysis, null, 2);
  }

  results.push({
    json: {
      username: original.username,
      full_name: original.full_name,
      instagram_url: original.instagram_url,
      is_verified: original.is_verified,
      is_private: original.is_private,
      analysis_report: report
    }
  });
}
return results;
